const body = $input.first().json;

// Parse Twilio inbound SMS or voice call webhook fields
const from = body.From || body.from || '';
const to = body.To || body.to || '';
const msgBody = body.Body || body.body || '';
const callStatus = body.CallStatus || body.call_status || '';
const callerName = body.CallerName || body.caller_name || '';
const callSid = body.CallSid || body.call_sid || '';
const msgSid = body.MessageSid || body.message_sid || '';

// Detect event type
const isCall = !!(callSid || callStatus);
const isSms = !!(msgSid || msgBody);
const eventType = isCall ? 'inbound_call' : 'inbound_sms';

// Clean phone number
const phone = from.replace(/[^\d+]/g, '');

// Try to extract name from SMS body: "Hi my name is John Smith"
let first_name = callerName.split(' ')[0] || '';
let last_name = callerName.split(' ').slice(1).join(' ') || '';

// Simple service keyword detection from SMS body
const bodyLower = msgBody.toLowerCase();
let service = '';
if (bodyLower.includes('mow') || bodyLower.includes('lawn')) service = 'lawn-mowing';
else if (bodyLower.includes('fertil')) service = 'fertilization';
else if (bodyLower.includes('aerat')) service = 'aeration';
else if (bodyLower.includes('hardscap') || bodyLower.includes('patio')) service = 'hardscaping';
else if (bodyLower.includes('cleanup') || bodyLower.includes('leaf')) service = 'cleanup';
else if (bodyLower.includes('snow') || bodyLower.includes('plow')) service = 'snow-removal';
else if (bodyLower.includes('gutter')) service = 'gutter-cleaning';
else if (bodyLower.includes('irrig') || bodyLower.includes('sprinkler')) service = 'irrigation';

return {
  json: {
    phone,
    first_name,
    last_name,
    source: 'phone',
    event_type: eventType,
    is_call: isCall,
    is_sms: isSms,
    message_body: msgBody,
    call_sid: callSid,
    message_sid: msgSid,
    twilio_to: to,
    service,
    raw_payload: JSON.stringify(body)
  }
};

const insertResult = $('Insert Phone Lead').first().json;
const lead_id = Array.isArray(insertResult) ? (insertResult[0] && insertResult[0].id) : (insertResult && insertResult.id);

return {
  json: {
    success: true,
    lead_id: lead_id || null,
    source: 'phone',
    sms_reply_sent: true
  }
};
